<div class="card-dark"><h5><?= $item?'Editar':'Nuevo' ?> material</h5><form method="post" enctype="multipart/form-data" action="<?= url('materiales/guardar') ?>" class="row g-2"><?= csrf_field() ?><input type="hidden" name="id" value="<?= e($item['id']??'') ?>"><div class="col-md-3"><label>Código interno</label><input required class="form-control" name="codigo_interno" value="<?= e($item['codigo_interno']??'') ?>"></div><div class="col-md-5"><label>Nombre material</label><input required class="form-control" name="nombre_material" value="<?= e($item['nombre_material']??'') ?>"></div><div class="col-md-4"><label>Categoría</label><select class="form-select" name="categoria_id"><option value="">Sin categoría</option><?php foreach($cats as $c): ?><option value="<?= $c['id'] ?>" <?= ($item['categoria_id']??'')==$c['id']?'selected':'' ?>><?= e($c['nombre']) ?></option><?php endforeach; ?></select></div><div class="col-md-2"><label>Unidad</label><input class="form-control" name="unidad_medida" value="<?= e($item['unidad_medida']??'un') ?>"></div><div class="col-md-2"><label>Stock</label><input type="number" step="0.01" class="form-control" name="stock_actual" value="<?= e($item['stock_actual']??0) ?>"></div><div class="col-md-2"><label>Mínimo</label><input type="number" step="0.01" class="form-control" name="stock_minimo" value="<?= e($item['stock_minimo']??0) ?>"></div><div class="col-md-3"><label>Foto</label><input type="file" class="form-control" name="foto" accept=".jpg,.jpeg,.png,.webp"></div><div class="col-md-3"><label>Estado</label><select class="form-select" name="estado"><option>activo</option><option>inactivo</option></select></div><div class="col-12"><label>Descripción</label><textarea class="form-control" name="descripcion"><?= e($item['descripcion']??'') ?></textarea></div><div class="col-12"><button class="btn btn-seim">Guardar</button></div></form></div>
